// API base URL — uses CRA proxy in dev, set REACT_APP_API_URL in production
export const API_BASE_URL = process.env.REACT_APP_API_URL || '';

// Local storage keys
export const TOKEN_KEY = 'careerpilot_token';
export const USER_KEY  = 'careerpilot_user';

// Route paths — single source of truth
export const ROUTES = {
  HOME:       '/',
  LOGIN:      '/login',
  REGISTER:   '/register',
  DASHBOARD:  '/dashboard',
  RESUME:     '/resume',
  CODING:     '/coding',
  INTERVIEW:  '/interview',
  CAREER:     '/career',
  SKILL_GAP:  '/skill-gap',
};

// Dashboard feature cards
export const FEATURE_CARDS = [
  {
    id: 'resume',
    title: 'Resume Analysis',
    description: 'Get AI-powered feedback on your resume and stand out to recruiters.',
    icon: '📄',
    path: ROUTES.RESUME,
    color: '#2563EB',
    available: false,
  },
  {
    id: 'coding',
    title: 'Coding Practice',
    description: 'Solve real interview problems with AI hints and explanations.',
    icon: '💻',
    path: ROUTES.CODING,
    color: '#7C3AED',
    available: false,
  },
  {
    id: 'interview',
    title: 'Mock Interview',
    description: 'Practice with an AI interviewer and receive instant feedback.',
    icon: '🎤',
    path: ROUTES.INTERVIEW,
    color: '#0891B2',
    available: false,
  },
  {
    id: 'career',
    title: 'Career Guidance',
    description: 'Get personalised career roadmaps and industry insights.',
    icon: '🧭',
    path: ROUTES.CAREER,
    color: '#059669',
    available: false,
  },
  {
    id: 'skill-gap',
    title: 'Skill Gap Analysis',
    description: 'Identify missing skills and get a targeted learning plan.',
    icon: '📊',
    path: ROUTES.SKILL_GAP,
    color: '#D97706',
    available: false,
  },
];
